class Solution:
    def maxProduct(self, nums):
        n = len(nums)
        R = 100000
        cand = {R, -R}
        best = None
        for r in range(n):
            original = nums[r]
            for x in cand:
                nums[r] = x
                arr = sorted(nums)
                p1 = arr[-1] * arr[-2] * arr[-3]
                p2 = arr[0] * arr[1] * arr[-1]
                cur = max(p1, p2)
                if best is None or cur > best:
                    best = cur
            nums[r] = original
        return best

