var maxProduct = function(nums) {
    const n = nums.length;
    const R = 100000;
    const arr = nums.slice().sort((a, b) => a - b);
    let best = null;
    if (n >= 4) {
        const p1 = arr[n-1] * arr[n-2] * arr[n-3];
        const p2 = arr[0] * arr[1] * arr[n-1];
        best = Math.max(p1, p2);
    }
    const pa = Math.max(arr[n-1]*arr[n-2], arr[0]*arr[1], arr[0]*arr[n-1]);
    const pi = Math.min(arr[n-1]*arr[n-2], arr[0]*arr[1], arr[0]*arr[n-1]);
    const case2 = Math.max(pa, -pi) * R;
    if (best === null || case2 > best) best = case2;
    return best;
};
